SELECT id, recording_id, user_id, item_id, label, grammar_type, forgetting_score, recommendation,
       mastery_level, next_review_at, score_source, updated_at
FROM grammar_weak_points
WHERE user_id = #{userId}

    AND grammar_type = #{grammarType}

ORDER BY forgetting_score DESC

SELECT id, recording_id, user_id, item_id, label, grammar_type, forgetting_score, recommendation,
       mastery_level, next_review_at, score_source, updated_at
FROM grammar_weak_points
WHERE user_id = #{userId}
ORDER BY forgetting_score DESC
LIMIT #{limit}
